const CURRENCY = "৳";
const FREE_DELIVERY_THRESHOLD = 1000;
const DELIVERY_INSIDE_DHAKA = 60;
const DELIVERY_OUTSIDE_DHAKA = 120;

document.addEventListener('DOMContentLoaded', () => {
  // Page Loader
  const loader = document.getElementById('page-loader');
  if (loader) {
    setTimeout(() => {
      loader.style.opacity = '0';
      setTimeout(() => loader.remove(), 500);
    }, 1000);
  }

  // Sticky Header
  const header = document.querySelector('.site-header');
  if (header) {
    window.addEventListener('scroll', () => {
      if (window.scrollY > 50) {
        header.classList.add('scrolled');
      } else {
        header.classList.remove('scrolled');
      }
    });
  }

  // Scroll to Top
  const scrollTopBtn = document.getElementById('scroll-top');
  if (scrollTopBtn) {
    window.addEventListener('scroll', () => {
      if (window.scrollY > 400) {
        scrollTopBtn.classList.add('visible');
      } else {
        scrollTopBtn.classList.remove('visible');
      }
    });
    scrollTopBtn.addEventListener('click', () => {
      window.scrollTo({ top: 0, behavior: 'smooth' });
    });
  }

  // Fade-in Animation
  const observerOptions = {
    root: null,
    rootMargin: '0px',
    threshold: 0.1
  };

  const observer = new IntersectionObserver((entries, observer) => {
    entries.forEach(entry => {
      if (entry.isIntersecting) {
        entry.target.classList.add('is-visible');
        observer.unobserve(entry.target);
      }
    });
  }, observerOptions);

  document.querySelectorAll('.fade-in-section').forEach(section => {
    observer.observe(section);
  });

  // Mobile Menu
  const mobileMenuBtn = document.getElementById('mobile-menu-btn');
  const mobileMenu = document.getElementById('mobile-menu');
  const mobileMenuClose = document.getElementById('mobile-menu-close');

  if (mobileMenuBtn && mobileMenu && mobileMenuClose) {
    mobileMenuBtn.addEventListener('click', () => {
      mobileMenu.classList.add('active');
    });
    mobileMenuClose.addEventListener('click', () => {
      mobileMenu.classList.remove('active');
    });
  }

  // Cart Drawer
  const cartBtn = document.getElementById('cart-btn');
  const cartDrawer = document.getElementById('cart-drawer');
  const cartClose = document.getElementById('cart-close');
  const cartOverlay = document.getElementById('cart-overlay');

  if (cartBtn && cartDrawer && cartClose && cartOverlay) {
    cartBtn.addEventListener('click', (e) => {
      e.preventDefault();
      cartDrawer.classList.add('active');
      cartOverlay.classList.add('active');
    });
    
    const closeCart = () => {
      cartDrawer.classList.remove('active');
      cartOverlay.classList.remove('active');
    };
    
    cartClose.addEventListener('click', closeCart);
    cartOverlay.addEventListener('click', closeCart);
  }

  // Render products on home page
  const newArrivalsGrid = document.getElementById('new-arrivals-grid');
  if (newArrivalsGrid) {
    const newProducts = products.filter(p => p.badge === 'New').slice(0, 6);
    if (newProducts.length < 6) {
      newProducts.push(...products.filter(p => p.badge !== 'New').slice(0, 6 - newProducts.length));
    }
    renderProducts(newProducts, newArrivalsGrid);
  }

  const bestsellersGrid = document.getElementById('bestsellers-grid');
  if (bestsellersGrid) {
    const saleProducts = products.filter(p => p.badge === 'Sale').slice(0, 6);
    if (saleProducts.length < 6) {
      saleProducts.push(...products.filter(p => p.badge !== 'Sale').slice(0, 6 - saleProducts.length));
    }
    renderProducts(saleProducts, bestsellersGrid);
  }

  // Render shop page products
  const shopGrid = document.getElementById('shop-grid');
  if (shopGrid) {
    renderProducts(products, shopGrid);
  }

  // Update cart count on load
  if (typeof updateCartCount === 'function') {
    updateCartCount();
  }
});

function renderProducts(productArray, container) {
  container.innerHTML = productArray.map(product => {
    const priceDisplay = product.salePrice 
      ? `<del>${CURRENCY} ${product.price}</del> ${CURRENCY} ${product.salePrice}`
      : `${CURRENCY} ${product.price}`;
      
    const badgeHtml = product.badge 
      ? `<div class="product-badge ${product.badge.toLowerCase()}">${product.badge}</div>` 
      : '';

    return `
      <div class="product-card">
        ${badgeHtml}
        <div class="product-image">
          <a href="product.html?id=${product.id}">
            <img src="${product.image}" alt="${product.name}">
          </a>
          <div class="product-actions">
            <button class="btn-add-cart" onclick="addToCart(${product.id}, event)">Add to Cart</button>
            <button class="btn-wishlist"><i class="lucide-heart">♡</i></button>
          </div>
        </div>
        <div class="product-info">
          <div class="product-category">${product.category}</div>
          <h3 class="product-title"><a href="product.html?id=${product.id}">${product.name}</a></h3>
          <div class="product-price">${priceDisplay}</div>
        </div>
      </div>
    `;
  }).join('');
}

function showToast(message) {
  const container = document.getElementById('toast-container');
  if (!container) return;
  
  const toast = document.createElement('div');
  toast.className = 'toast';
  toast.innerHTML = `<span>✓</span> ${message}`;
  
  container.appendChild(toast);
  
  // Trigger reflow
  toast.offsetHeight;
  toast.classList.add('show');
  
  setTimeout(() => {
    toast.classList.remove('show');
    setTimeout(() => toast.remove(), 300);
  }, 3000);
}

